  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
  padding: 30px;
  background: white;
  border-radius: 16px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
}

.dashboard-panel .header-left {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.dashboard-panel .header-title {
  font-size: 28px;
  font-weight: 700;
  color: #2d3748;
}

.dashboard-panel .header-time {
  font-size: 16px;
  color: #718096;
  font-family: 'Menlo', 'Monaco', monospace;
}

.dashboard-panel .filter-tabs {
  display: flex;
  gap: 10px;
}

.dashboard-panel .filter-tab {
  padding: 10px 20px;
  border: 2px solid #e2e8f0;
  border-radius: 10px;
  background: white;
  color: #4a5568;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.dashboard-panel .filter-tab:hover {
  border-color: #667eea;
  color: #667eea;
}

.dashboard-panel .filter-tab.active {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border-color: transparent;
}

/* 统计卡片网格 */
.dashboard-panel .stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin-bottom: 30px;
}

.dashboard-panel .stat-card {
  background: white;
  border-radius: 16px;
  padding: 25px;
  display: flex;
  align-items: center;
  gap: 20px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  transition: all 0.3s ease;
}

.dashboard-panel .stat-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
}

.dashboard-panel .stat-card.total {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
}

.dashboard-panel .stat-card.completed {
  background: linear-gradient(135deg, #48bb78 0%, #38a169 100%);
  color: white;
}

.dashboard-panel .stat-card.workload {
  background: linear-gradient(135deg, #4299e1 0%, #3182ce 100%);
  color: white;
}

.dashboard-panel .stat-card.efficiency {
  background: linear-gradient(135deg, #ed8936 0%, #dd6b20 100%);
  color: white;
}

.dashboard-panel .stat-icon {
  font-size: 48px;
}

.dashboard-panel .stat-value {
  font-size: 32px;
  font-weight: 700;
  line-height: 1.2;
}

.dashboard-panel .stat-label {
  font-size: 14px;
  opacity: 0.9;
}

/* 员工卡片网格 */
.dashboard-panel .members-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 25px;
  margin-bottom: 30px;
}

.dashboard-panel .member-card {
  background: white;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  transition: all 0.3s ease;
  border: 3px solid;
}

.dashboard-panel .member-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
}

/* 员工头部 */
.dashboard-panel .member-header {
  padding: 20px 25px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  color: white;
}

.dashboard-panel .member-avatar {
  font-size: 40px;
}

.dashboard-panel .member-info {
  display: flex;
  flex-direction: column;
}

.dashboard-panel .member-name {
  font-size: 20px;
  font-weight: 700;
  margin-bottom: 4px;
}

.dashboard-panel .member-role {
  font-size: 13px;
  opacity: 0.9;
}

.dashboard-panel .progress-ring svg {
  animation: rotate 2s linear infinite;
}

@keyframes rotate {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.dashboard-panel .progress-ring circle:last-child {
  animation: fill 1s ease forwards;
}

@keyframes fill {
  from {
    stroke-dashoffset: 163.36;
  }
  to {
    stroke-dashoffset: 0;
  }
}

/* 员工内容 */
.dashboard-panel .member-body {
  padding: 25px;
}

.dashboard-panel .member-stats {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 15px;
  margin-bottom: 25px;
  padding-bottom: 25px;
  border-bottom: 2px solid #e2e8f0;
}

.dashboard-panel .stat-item {
  text-align: center;
}

.dashboard-panel .stat-label {
  display: block;
  font-size: 13px;
  color: #718096;
  margin-bottom: 8px;
}

.dashboard-panel .stat-val {
  display: block;
  font-size: 24px;
  font-weight: 700;
  color: #2d3748;
}

.dashboard-panel .stat-val.status-completed {
  color: #48bb78;
}

/* 任务列表 */
.dashboard-panel .tasks-title {
  font-size: 16px;
  font-weight: 600;
  color: #2d3748;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 2px solid #e2e8f0;
}

.dashboard-panel .tasks-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.dashboard-panel .task-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 15px;
  background: #f7fafc;
  border-radius: 10px;
}

.dashboard-panel .task-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.dashboard-panel .task-number {
  width: 24px;
  height: 24px;
  background: #e2e8f0;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  color: #4a5568;
  flex-shrink: 0;
}

.dashboard-panel .task-name {
  font-size: 14px;
  color: #2d3748;
}

.dashboard-panel .task-right {
  display: flex;
  align-items: center;
  gap: 15px;
}

.dashboard-panel .task-status {
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
}

.dashboard-panel .task-status.completed {
  background: #c6f6d5;
  color: #22543d;
}

.dashboard-panel .task-status.in-progress {
  background: #fefcbf;
  color: #744210;
}

.dashboard-panel .task-duration {
  font-family: 'Menlo', 'Monaco', monospace;
  font-size: 13px;
  color: #718096;
}

/* 工作流程图 */
.dashboard-panel .workflow-section {
  background: white;
  border-radius: 20px;
  padding: 30px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
}

.dashboard-panel .section-title {
  font-size: 24px;
  font-weight: 700;
  color: #2d3748;
  margin-bottom: 30px;
  text-align: center;
}

.dashboard-panel .workflow-diagram {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  flex-wrap: wrap;
}

.dashboard-panel .workflow-node {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  padding: 20px 30px;
  background: #f7fafc;
  border-radius: 16px;
  border: 2px solid #e2e8f0;
  min-width: 120px;
  transition: all 0.3s ease;
}

.dashboard-panel .workflow-node:hover {
  transform: scale(1.05);
  border-color: #667eea;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.2);
}

.dashboard-panel .workflow-node.success {
  background: linear-gradient(135deg, #48bb78 0%, #38a169 100%);
  color: white;
  border-color: transparent;
}

.dashboard-panel .node-icon {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  background: #e2e8f0;
  color: #2d3748;
}

.dashboard-panel .node-label {
  font-size: 14px;
  font-weight: 600;
  color: #2d3748;
}

.dashboard-panel .node-time {
  font-family: 'Menlo', 'Monaco', monospace;
  font-size: 12px;
  color: #718096;
}

.dashboard-panel .workflow-node.success .node-label,
.dashboard-panel .workflow-node.success .node-time {
  color: white;
}

.dashboard-panel .workflow-arrow {
  font-size: 24px;
  color: #cbd5e0;
  animation: bounce 1.5s infinite;
}

@keyframes bounce {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(5px);
  }
}

/* 响应式 */
@media (max-width: 1200px) {
  .dashboard-panel .stats-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .dashboard-panel .members-grid {
    grid-template-columns: 1fr;
  }

  .dashboard-panel .workflow-diagram {
    flex-direction: column;
  }

  .dashboard-panel .workflow-arrow {
    transform: rotate(90deg);
  }
}

@media (max-width: 768px) {
  .dashboard-panel .header-title {
    font-size: 20px;
  }

  .dashboard-panel .stats-grid {
    grid-template-columns: 1fr;
  }
}

